// Pump-due threshold (minutes). Matches the 2h Pump Reminder workflow; tweak here.
const PUMP_INTERVAL_MIN = 120;

const r = $input.first().json;
const now = Date.now();

function agoStr(ts) {
  if (!ts) return null;
  const min = Math.floor((now - new Date(ts).getTime()) / 60000);
  if (min < 1) return 'now';
  const h = Math.floor(min / 60), m = min % 60;
  return h > 0 ? (h + 'h' + m + 'm') : (m + 'm');
}
function inStr(min) {
  if (min >= 60) return Math.floor(min / 60) + 'h' + (min % 60) + 'm';
  return min + 'm';
}

const feedAgo = agoStr(r.last_feed);
const pumpAgo = agoStr(r.last_pump);

const l1 = feedAgo ? ('Feed ' + feedAgo + ' ago') : 'Feed: --';
const l2 = pumpAgo ? ('Pump ' + pumpAgo + ' ago') : 'Pump: --';

let l3 = '';
let alert = '0';
if (r.last_pump) {
  const sincePump = Math.floor((now - new Date(r.last_pump).getTime()) / 60000);
  const due = PUMP_INTERVAL_MIN - sincePump;
  if (due <= 0) { l3 = 'Pump due now'; alert = '1'; }
  else { l3 = 'Pump in ' + inStr(due); }
}

const display = JSON.stringify({ l1: l1, l2: l2, l3: l3 });
return [{ json: { display: display, alert: alert, l1: l1, l2: l2, l3: l3 } }];
